+//! Neural Engine (NPU) Matrix Multiplication via Metal Performance Shaders
+//!
+//! Integrates Apple's Neural Engine (ANE) for matmul operations.
+//! The NPU shares the same L2 cache as CPU and GPU, enabling 3-way heterogeneous computing.
+//!
+//! Architecture:
+//!   CPU: Manages control flow, handles small ops
+//!   GPU: Dequantization kernels (Q2_K → BF16)
+//!   NPU: Matrix multiplications (matmul via MPS)
+//!   All three share 16MB L2 cache + unified memory
+//!
+//! Performance Target:
+//!   Current: ~17ms per layer (GPU dequant + GPU compute)
+//!   Target:  ~5-8ms per layer (GPU dequant + NPU matmul)
+//!   Speedup: 2-3x
+
+const std = @import("std");
+const objc = @import("metal/objc.zig");
+const BF16 = @import("gguf_loader.zig").BF16;
+
+const log = std.log.scoped(.npu_matmul);
+
+/// NPU Matmul Engine using Metal Performance Shaders
+pub const NPUMatmulEngine = struct {
+    allocator: std.mem.Allocator,
+    device: objc.MTLDevice,
+    command_queue: objc.MTLCommandQueue,
+
+    // MPS Graph API (automatic ANE routing)
+    // Note: MPS automatically routes FP16/BF16 matmul to Neural Engine
+    // We use Metal's lower-level API to interface with MPS
+
+    const Self = @This();
+
+    /// Initialize NPU matmul engine
+    pub fn init(allocator: std.mem.Allocator, device: objc.MTLDevice) !*Self {
+        log.info("Initializing NPU Matmul Engine (Metal Performance Shaders)", .{});
+
+        // Verify device supports MPS operations
+        // Neural Engine is available on M1+ chips
+        const device_name = objc.deviceGetName(device);
+        log.info("Device: {s}", .{device_name});
+
+        // Create command queue for NPU operations
+        const queue = objc.deviceNewCommandQueue(device) orelse {
+            return error.CommandQueueFailed;
+        };
+
+        var self = try allocator.create(Self);
+        self.* = Self{
+            .allocator = allocator,
+            .device = device,
+            .command_queue = queue,
+        };
+
+        log.info("NPU Matmul Engine initialized (ANE routing via MPS)", .{});
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        objc.release(self.command_queue);
+        self.allocator.destroy(self);
+    }
+
+    /// Matrix multiplication: C = A × B
+    ///
+    /// Uses Metal Performance Shaders (MPS) which automatically routes to Neural Engine.
+    /// MPS Graph API will use ANE for FP16/BF16 matmul on Apple Silicon.
+    ///
